SELECT A.BROKER_CHARGE_CODE brokerChargeCode, A.BROKER_CHARGE_NAME employeeName FROM MEDIATE_CHARGE_INFO A WHERE A.DELETE_FLG = '0' AND A.BROKER_CODE = #{req.brokerCode}
AND A.BROKER_BRANCH_CODE = #{req.subBrokerId}
ORDER BY A.BROKER_BRANCH_CODE ASC


SELECT
COUNT(*) searchResultCount
FROM TB_MED_USERS A
LEFT OUTER JOIN TB_MED_USERS_PRIV B
ON A.USER_ID = B.USER_ID
WHERE (
A.USER_ID = #{req.userId}
AND A.BROKER_ID = #{req.brokerCode}
AND A.EMPLOYEE_ID = #{req.employeeId}
) OR (
B.USER_ID = #{req.userId}
AND B.BROKER_ID = #{req.brokerCode}
AND B.EMPLOYEE_ID = #{req.employeeId}
AND B.DELETE_FLG = '0'
)
